INSERT INTO approved_questions (question, answer, topic, difficulty) VALUES ("What are the major improvements in Spring Boot 3.x and how do they impact microservices development?", "Spring Boot 3.x brings significant improvements:\n\n1. **Java 17+ Baseline**: Requires Java 17 minimum, Java 21 recommended\n2. **Native Image Support**: Enhanced GraalVM compilation for faster startup\n3. **Observability**: Built-in Micrometer Tracing and improved metrics\n4. **Jakarta EE Migration**: Full migration from javax.* to jakarta.*\n5. **Spring Security 6**: New security defaults and OAuth2 improvements\n\nImpact on microservices:\n- Smaller, faster native images (startup in milliseconds)\n- Better observability out of the box\n- Improved security posture\n- Enhanced resilience patterns", "Spring Boot", "Medium");
INSERT INTO approved_questions (question, answer, topic, difficulty) VALUES ("Explain Virtual Threads in Java 21 and their benefits for high-concurrency applications.", "Virtual Threads are lightweight threads managed by the JVM:\n\n**Key Features**:\n- Managed by JVM, not OS\n- Millions of virtual threads possible\n- Dramatically simpler concurrency code\n- Much higher throughput for I/O-bound tasks\n\n**Example**:\n```java\nExecutorService executor = Executors.newVirtualThreadPerTaskExecutor();\nexecutor.submit(() -> {\n    // I/O-bound task\n    return httpClient.send(request);\n});\n```\n\n**Benefits**:\n- Reduced resource consumption\n- Easier debugging and profiling\n- Ideal for I/O-bound operations\n- Solves thread starvation problems", "Java", "Hard");
INSERT INTO approved_questions (question, answer, topic, difficulty) VALUES ("Design an optimized database schema for a high-volume e-commerce application with proper indexing and partitioning strategies.", "Optimized schema design:\n\n```sql\n-- Orders table with range partitioning\nCREATE TABLE orders (\n    order_id NUMBER PRIMARY KEY,\n    user_id NUMBER NOT NULL,\n    status VARCHAR2(50),\n    total_amount NUMBER(10,2),\n    created_at TIMESTAMP\n)\nPARTITION BY RANGE (created_at) (\n    PARTITION orders_2026_01 VALUES LESS THAN (TO_DATE('2026-02-01', 'YYYY-MM-DD')),\n    PARTITION orders_2026_02 VALUES LESS THAN (TO_DATE('2026-03-01', 'YYYY-MM-DD'))\n);\n\n-- Indexes for performance\nCREATE INDEX idx_orders_user_id ON orders(user_id);\nCREATE INDEX idx_orders_status_date ON orders(status, created_at);\n```\n\n**Strategies**:\n- Range partition by date for orders\n- Composite indexes for multi-column queries\n- Archive old partitions\n- Use sequences for ID generation", "Oracle", "Hard");
INSERT INTO approved_questions (question, answer, topic, difficulty) VALUES ("Explain standalone components in Angular 17+ and when to use them vs NgModule-based architecture.", "**Standalone Components** (Angular 17+):\n- No NgModule declarations needed\n- Individual imports for dependencies\n- Simpler, more modular structure\n- Better tree-shaking\n\n```typescript\n@Component({\n  selector: 'app-product',\n  standalone: true,\n  imports: [CommonModule, MatButtonModule],\n  template: `...`\n})\nexport class ProductComponent {}\n```\n\n**NgModule-based**:\n- Centralized declarations\n- Shared imports across components\n- Better for large existing apps\n\n**When to use**:\n- Standalone: New projects, libraries, smaller components\n- NgModule: Existing large apps, complex DI scenarios", "Angular", "Medium");
INSERT INTO approved_questions (question, answer, topic, difficulty) VALUES ("Compare AWS Lambda vs ECS Fargate for microservices deployment.", "**AWS Lambda**:\nPros:\n- True serverless, pay-per-execution\n- Automatic scaling\n- Event-driven architecture\n\nCons:\n- 15-minute execution limit\n- Cold start latency\n- Limited memory/disk\n\n**ECS Fargate**:\nPros:\n- No execution time limit\n- Full control over runtime\n- Better for long-running processes\n\nCons:\n- Per-second billing\n- Requires containerization\n- More complex setup\n\n**Use Lambda for**: Event processing, short-lived functions, variable workloads\n**Use Fargate for**: Long-running apps, complex microservices, persistent connections", "AWS", "Medium");
